INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('1b25eedd-b782-4fff-ac3a-4ef6968425b0', '0cceaa41-5964-468d-9835-d1c67b7f1190', 'You''re in great shape 🥦', 'Your habits suggest you''re already eating a mostly whole-food diet and staying well clear of ultra-processed traps. Keep doing what you''re doing — Olive can help you level up even further.', 'See How Olive Works', 'https://oliveapp.com/', 0, 20, '2026-04-28 19:06:24.310827+00', '2026-04-28 19:06:24.310827+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('85c942ea-7d4e-4bc7-8152-5d0c22218308', '0cceaa41-5964-468d-9835-d1c67b7f1190', 'Pretty solid, with some sneaky gaps 🙂', 'You''ve got good instincts, but a few ultra-processed habits are creeping in. A little more awareness around ingredients and cooking could make a real difference.', 'Try Olive Free', 'https://oliveapp.com/', 21, 38, '2026-04-28 19:06:24.310827+00', '2026-04-28 19:06:24.310827+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('94ea9461-0292-4727-b3f1-1dabb9f9acdd', '0cceaa41-5964-468d-9835-d1c67b7f1190', 'Ultra-processed food is a regular guest at your table 🍟', 'You''re leaning heavily on processed and convenient options — which is super common, but it adds up fast. Olive was built exactly for this: helping you spot better swaps without overhauling your life.', 'Start Using Olive Today', 'https://oliveapp.com/#features', 39, 54, '2026-04-28 19:06:24.310827+00', '2026-04-28 19:06:24.310827+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('f1f27c1b-723c-435b-8dd0-f8d12a084b89', '0cceaa41-5964-468d-9835-d1c67b7f1190', 'Ultra-processed food is basically running the show 🚨', 'Your diet is heavily shaped by ultra-processed foods, and your body is probably feeling it. The good news: small, consistent swaps add up quickly. Olive is designed to make that easy.', 'Get Started with Olive', 'https://oliveapp.com/#features', 55, 65, '2026-04-28 19:06:24.310827+00', '2026-04-28 19:06:24.310827+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('cc3cf747-b498-4ab8-a353-1b21688036f6', '46a5596c-6c05-435b-a181-872892ec074f', 'The Label Detective', 'You read ingredient lists like they''re crime novels. You know the difference between maltodextrin and dextrose, and frankly, you''re a little suspicious of anything that doesn''t have a clearly sourced supply chain. We respect you. (And slightly fear you.)', 'See how Olive thinks about food', 'https://oliveapp.com/#features', 28, 50, '2026-04-28 19:07:25.838577+00', '2026-04-28 19:07:25.838577+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('88c6aaf9-09ff-474c-accb-bfc526e07f88', '46a5596c-6c05-435b-a181-872892ec074f', 'The Curious Omnivore', 'You like knowing what you''re eating, but you''re not about to ruin a meal by overthinking it. You''ll try almost anything once and you''ve got a growing list of "wait, what was that dish called?" moments. Basically the ideal dinner party guest.', 'Explore Olive', 'https://oliveapp.com/', 18, 27, '2026-04-28 19:07:25.838577+00', '2026-04-28 19:07:25.838577+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('7afa022a-f384-41c6-8e48-a047d5d593eb', '46a5596c-6c05-435b-a181-872892ec074f', 'The Creature of Comfort', 'Your top 10 meals have been your top 10 meals for years, and that''s not a bug — it''s a feature. You know what you like, you''re efficient about getting it, and you''re never disappointed. Bold strategy. It''s mostly working.', 'Discover something new with Olive', 'https://oliveapp.com/#features', 8, 17, '2026-04-28 19:07:25.838577+00', '2026-04-28 19:07:25.838577+00');
INSERT INTO public.result (id, quiz_id, title_text, description, cta_text, cta_url, range_lo, range_hi, created_at, updated_at) VALUES ('a6e75a98-5354-4318-8dc7-a19207308a2f', '46a5596c-6c05-435b-a181-872892ec074f', 'The Blissfully Unaware', 'Your fridge is a mystery, your snack choices are vibes-based, and you once ate something that you''re pretty sure expired but it tasted fine so. You''re free in a way most of us will never understand. Godspeed.', 'Meet Olive — your new food BFF', 'https://oliveapp.com/', 0, 7, '2026-04-28 19:07:25.838577+00', '2026-04-28 19:07:25.838577+00');
